using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net.Http;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;

namespace WebhookProxy.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class ProxyController : ControllerBase
    {
        private readonly Dictionary<string, string> _webhooks = new Dictionary<string, string>();

        [HttpGet("register/{url}")]
        public IActionResult Register(string url)
        {
            if (!_webhooks.ContainsKey(url))
                _webhooks[url] = Request.HttpContext.Request.Host.ToUriComponent();

            return Ok($"Webhook '{url}' registered.");
        }

        [HttpGet("{url}")]
        public async Task<IActionResult> Forward(string url)
        {
            if (_webhooks.TryGetValue(url, out var proxyUrl))
            {
                using var client = new HttpClient();
                using var response = await client.GetAsync($"http://{proxyUrl}/{Uri.EscapeDataString(url)}");

                response.EnsureSuccessStatusCode();
                return Content(await response.Content.ReadAsStringAsync(), "text/plain");
            }

            return NotFound();
        }
    }
}